dashboard.definition:
{
    "title": "Content Governance and eDiscovery Controls",
    "description": "Monitor sensitive content retrieval and deletion actions.",
    "inputs": {
        "input_time": {
            "type": "input.timerange",
            "title": "Time Range",
            "options": { "token": "time", "defaultValue": "-30d@d,now" }
        }
    },
    "dataSources": {
        "ds_retrieval_time": {
            "type": "ds.search",
            "name": "Content retrieval over time",
            "options": {
                "query": "index=cloud_llm_apis sourcetype=anthropic:compliance:activity 'ai.risk.content_retrieved'=true | timechart span=1d count as content_retrievals",
                "queryParameters": { "earliest": "$time.earliest$", "latest": "$time.latest$" }
            }
        },
        "ds_deletions": {
            "type": "ds.search",
            "name": "Deletion actions",
            "options": {
                "query": "index=cloud_llm_apis sourcetype=anthropic:compliance:activity 'ai.risk.deletion_action'=true | timechart span=1d count as deletions",
                "queryParameters": { "earliest": "$time.earliest$", "latest": "$time.latest$" }
            }
        },
        "ds_retrieval_actor": {
            "type": "ds.search",
            "name": "Retrievals by actor",
            "options": {
                "query": "index=cloud_llm_apis sourcetype=anthropic:compliance:activity 'ai.risk.content_retrieved'=true | stats count by 'ai.actor.email' 'ai.event.type' 'ai.governance.object_type' 'ai.actor.ip' | sort -count | rename ai.actor.email as actor_email ai.event.type as event_type ai.governance.object_type as object_type ai.actor.ip as actor_ip",
                "queryParameters": { "earliest": "$time.earliest$", "latest": "$time.latest$" }
            }
        },
        "ds_offhours": {
            "type": "ds.search",
            "name": "Retrievals outside business hours",
            "options": {
                "query": "index=cloud_llm_apis sourcetype=anthropic:compliance:activity 'ai.risk.content_retrieved'=true | eval hour=tonumber(strftime(_time,\"%H\")), wday=strftime(_time,\"%A\") | where hour<8 OR hour>18 OR wday=\"Saturday\" OR wday=\"Sunday\" | stats count by 'ai.actor.email' | sort -count | rename ai.actor.email as actor_email",
                "queryParameters": { "earliest": "$time.earliest$", "latest": "$time.latest$" }
            }
        },
        "ds_ratio": {
            "type": "ds.search",
            "name": "Compliance read ratio",
            "options": {
                "query": "index=cloud_llm_apis sourcetype=anthropic:compliance:activity | eval is_read=if('ai.risk.content_retrieved'=\"true\",1,0) | stats sum(is_read) as reads count as total | eval read_ratio_pct=round(reads/total*100,2) | fields read_ratio_pct",
                "queryParameters": { "earliest": "$time.earliest$", "latest": "$time.latest$" }
            }
        }
    },
    "visualizations": {
        "viz_ratio": {
            "type": "splunk.singlevalue",
            "title": "Content Read Ratio (%)",
            "dataSources": { "primary": "ds_ratio" },
            "options": { "majorField": "read_ratio_pct", "unit": "%" }
        },
        "viz_retrieval_time": {
            "type": "splunk.area",
            "title": "Raw Content Retrievals Over Time",
            "dataSources": { "primary": "ds_retrieval_time" },
            "options": { "xField": "_time" }
        },
        "viz_deletions": {
            "type": "splunk.column",
            "title": "Delete-Capable Actions Over Time",
            "dataSources": { "primary": "ds_deletions" },
            "options": { "xField": "_time" }
        },
        "viz_retrieval_actor": {
            "type": "splunk.table",
            "title": "Content Retrieval by Actor",
            "dataSources": { "primary": "ds_retrieval_actor" }
        },
        "viz_offhours": {
            "type": "splunk.bar",
            "title": "Off-Hours Retrievals by Actor",
            "dataSources": { "primary": "ds_offhours" },
            "options": { "yField": "actor_email" }
        }
    },
    "layout": {
        "type": "grid",
        "globalInputs": [ "input_time" ],
        "structure": [
            { "item": "viz_ratio", "type": "block", "position": { "x": 0, "y": 0, "w": 400, "h": 200 } },
            { "item": "viz_retrieval_time", "type": "block", "position": { "x": 400, "y": 0, "w": 800, "h": 200 } },
            { "item": "viz_deletions", "type": "block", "position": { "x": 0, "y": 200, "w": 600, "h": 280 } },
            { "item": "viz_offhours", "type": "block", "position": { "x": 600, "y": 200, "w": 600, "h": 280 } },
            { "item": "viz_retrieval_actor", "type": "block", "position": { "x": 0, "y": 480, "w": 1200, "h": 340 } }
        ]
    }
}
